   149→void ActiveTcpListener::newActiveConnection(const Network::FilterChain& filter_chain,
   150→                                            Network::ServerConnectionPtr server_conn_ptr,
   151→                                            std::unique_ptr<StreamInfo::StreamInfo> stream_info) {
   152→  auto& active_connections = getOrCreateActiveConnections(filter_chain);
   153→  auto active_connection =
   154→      std::make_unique<ActiveTcpConnection>(active_connections, std::move(server_conn_ptr),
   155→                                            dispatcher().timeSource(), std::move(stream_info));
   156→  // If the connection is already closed, we can just let this connection immediately die.
   157→  if (active_connection->connection_->state() != Network::Connection::State::Closed) {
   158→    ENVOY_CONN_LOG(
   159→        debug, "new connection from {}", *active_connection->connection_,
   160→        active_connection->connection_->connectionInfoProvider().remoteAddress()->asString());
   161→    active_connection->connection_->addConnectionCallbacks(*active_connection);
   162→    LinkedList::moveIntoList(std::move(active_connection), active_connections.connections_);
   163→  }
   164→}
