    23→ActiveTcpSocket::~ActiveTcpSocket() {
    24→  accept_filters_.clear();
    25→
    26→  listener_.stats_.downstream_pre_cx_active_.dec();
    27→  // If the underlying socket is no longer attached, it means that it has been transferred to
    28→  // an active connection. In this case, the active connection will decrement the number
    29→  // of listener connections.
    30→  // TODO(mattklein123): In general the way we account for the number of listener connections
    31→  // is incredibly fragile. Revisit this by potentially merging ActiveTcpSocket and
    32→  // ActiveTcpConnection, having a shared object which does accounting (but would require
    33→  // another allocation, etc.).
    34→  if (socket_ != nullptr) {
    35→    listener_.decNumConnections();
    36→  }
    37→}
